import React from 'react'
import { createBrowserRouter, RouterProvider } from 'react-router-dom'
import Master from '../layouts/Master'
import Home from '../views/Home'

const About  = React.lazy(() => import('../views/About'))
const Contact  = React.lazy(() => import('../views/Contact'))
const Admin  = React.lazy(() => import('../views/Admin'))
const NotFound  = React.lazy(() => import('../views/NotFound'))

function index() {
  const Router = createBrowserRouter([
    {
      path: '/',
      element: <Master />,
      errorElement: <React.Suspense fallback="Loading"><NotFound /></React.Suspense>,
      children: [
        {
          index,
          element: <Home />
        },
        {
          path: '/',
          element: <Home />
        },
        {
          path: 'about',
          element: <React.Suspense fallback="Loading"><About /></React.Suspense>
        },
        {
          path: 'contact',
          element: <React.Suspense fallback="Loading"><Contact /></React.Suspense>
        },
        {
          path: 'admin',
          element: <React.Suspense fallback="Loading"><Admin /></React.Suspense>
        }
      ]
    }
  ])
  return (
    <div>
      <RouterProvider router={Router} />
    </div>
  )
}

export default index
